-- Zero out costs for SmileTel Xero services (they are revenue items, not supplier costs)
UPDATE services SET monthlyCost = 0.00 WHERE dataSource LIKE '%Xero%' AND supplierName = 'SmileTel';

-- Check how many were updated
SELECT COUNT(*) as updated_count FROM services WHERE dataSource LIKE '%Xero%' AND supplierName = 'SmileTel' AND monthlyCost = 0.00;

